export const EverestHorizontalIcon = (props: SvgIconProps) => {
  const {
    palette: { mode },
  } = useTheme();

  return mode === 'light' ? (
    <EverestHorizontalLightIcon {...props} />
  ) : (
    <EverestHorizontalDarkIcon {...props} />
  );
};

